from flask import Flask, request, jsonify, Response
from flask_cors import CORS
import requests, os, base64 as b64, io
from PIL import Image, ImageDraw, ImageFont
from datetime import datetime

app = Flask(__name__)
CORS(app)

@app.after_request
def ar(r):
    r.headers["Access-Control-Allow-Origin"] = "*"
    r.headers["Access-Control-Allow-Headers"] = "Content-Type"
    r.headers["Access-Control-Allow-Methods"] = "GET,POST,OPTIONS"
    return r

BOT_TOKEN = os.environ.get("TG_BOT_TOKEN","8601946674:AAGpvttyRBy7B81uU_frX8BQWk-N68lFTtQ")
GROUP_ID  = os.environ.get("TG_GROUP_ID","-1003900515439")

_HTML    = b64.b64decode("").decode("utf-8")
_TPL_B64 = ""

def make_poster(pct, date_str):
    tpl_bytes = b64.b64decode(_TPL_B64)
    img = Image.open(io.BytesIO(tpl_bytes)).copy()
    draw = ImageDraw.Draw(img)
    try:
        font_date = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 36)
        font_pct  = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 96)
    except:
        try:
            font_date = ImageFont.truetype("/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf", 36)
            font_pct  = ImageFont.truetype("/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf", 96)
        except:
            font_date = ImageFont.load_default()
            font_pct  = font_date
    sign = "+" if pct >= 0 else ""
    pct_str = f"{sign}{pct:.2f}%"
    # Datum: leere Box links (207, 730)
    draw.text((207, 730), date_str, fill="#ffffff", font=font_date, anchor="mm")
    # %: leere Box rechts (600, 614)
    draw.text((600, 614), pct_str, fill="#00dca8", font=font_pct, anchor="mm")
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return buf.getvalue()

@app.route("/")
def index():
    return Response(_HTML, mimetype="text/html")

@app.route("/health")
def health():
    return jsonify({"status":"ok","pillow":True})

@app.route("/test", methods=["GET","POST","OPTIONS"])
def test():
    if request.method=="OPTIONS": return jsonify({})
    r = requests.post(
        f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage",
        json={"chat_id":GROUP_ID,"text":"\U0001f916 *OneTrade Bot* \u2013 Verbindung erfolgreich! \u2705","parse_mode":"Markdown"},
        timeout=15)
    d = r.json()
    if d.get("ok"): return jsonify({"ok":True,"message":"Test-Nachricht gesendet!"})
    return jsonify({"ok":False,"error":d.get("description")}), 400

@app.route("/send", methods=["POST","OPTIONS"])
def send():
    if request.method=="OPTIONS": return jsonify({})
    try:
        data    = request.get_json(force=True,silent=True) or {}
        pct     = float(data.get("pct",0))
        gained  = float(data.get("gained",0))
        kapital = float(data.get("kapital",0))
        note    = str(data.get("note",""))
        date_str= str(data.get("date", datetime.now().strftime("%d.%m.%Y")))
        time_str= str(data.get("time",""))
        sign = "+" if pct >= 0 else ""
        emoji = "\U0001f4c8" if pct >= 0 else "\U0001f4c9"
        cap  = f"{emoji} *OneTrade \u2013 T\u00e4gliche Aussch\u00fcttung*\n\n"
        cap += f"\U0001f4c5 *Datum:* {date_str} | {time_str} Uhr\n"
        cap += "\u2501"*17+"\n"
        cap += f"\U0001f4b0 *Tagesgewinn:* `{sign}{pct:.4f}%`\n"
        if gained>0:  cap += f"\U0001f4b5 *Ausgesch\u00fcttet:* `{gained:,.2f} USDT`\n"
        if kapital>0: cap += f"\U0001f3e6 *Eingesetztes Kapital:* `{kapital:,.2f} USDT`\n"
        cap += "\u2501"*17+"\n"
        if note: cap += f"\U0001f4dd {note}\n"+"\u2501"*17+"\n"
        cap += "_Powered by OneTrade AI System_\n"
        cap += "_Vergangene Ergebnisse sind keine Garantie f\u00fcr die Zukunft._"
        # Poster serverseitig rendern
        try:
            png_bytes = make_poster(pct, date_str)
            r = requests.post(
                f"https://api.telegram.org/bot{BOT_TOKEN}/sendPhoto",
                files={"photo":("poster.png", png_bytes, "image/png")},
                data={"chat_id":GROUP_ID,"caption":cap,"parse_mode":"Markdown"},
                timeout=30)
        except Exception as img_err:
            r = requests.post(
                f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage",
                json={"chat_id":GROUP_ID,"text":cap,"parse_mode":"Markdown","disable_web_page_preview":True},
                timeout=15)
        d = r.json()
        if d.get("ok"): return jsonify({"ok":True,"with_image":True})
        return jsonify({"ok":False,"error":d.get("description","Fehler")}),400
    except Exception as e:
        return jsonify({"ok":False,"error":str(e)}),500

@app.route("/wallet")
def wallet():
    address  = request.args.get("address","0x17E384Fc02A4800e1cb8644CAB9daAeA9a2861A1")
    api_key  = os.environ.get("BSCSCAN_API_KEY","YourApiKeyToken")
    contract = "0x55d398326f99059fF775485246999027B3197955"
    try:
        r = requests.get(f"https://api.bscscan.com/api?module=account&action=tokenbalance&contractaddress={contract}&address={address}&tag=latest&apikey={api_key}",timeout=10)
        d = r.json()
        if d.get("status")=="1": return jsonify({"ok":True,"balance":int(d["result"])/1e18})
        return jsonify({"ok":False,"error":d.get("message")}),400
    except Exception as e:
        return jsonify({"ok":False,"error":str(e)}),500

if __name__=="__main__":
    app.run(host="0.0.0.0",port=int(os.environ.get("PORT",5000)))
